        - --plm-storage-url={{ .Values.nginxGateway.plmStorage.url }}
        {{- if .Values.nginxGateway.plmStorage.credentialsSecretName }}
        - --plm-storage-credentials-secret={{ .Values.nginxGateway.plmStorage.credentialsSecretName }}
        {{- end }}
        {{- if .Values.nginxGateway.plmStorage.tls.caSecretName }}
        - --plm-storage-ca-secret={{ .Values.nginxGateway.plmStorage.tls.caSecretName }}
        {{- end }}
        {{- if .Values.nginxGateway.plmStorage.tls.clientSSLSecretName }}
        - --plm-storage-client-ssl-secret={{ .Values.nginxGateway.plmStorage.tls.clientSSLSecretName }}
        {{- end }}
        {{- if .Values.nginxGateway.plmStorage.tls.insecureSkipVerify }}
        - --plm-storage-skip-verify
        {{- end }}
        {{- end }}
        {{- if .Capabilities.APIVersions.Has "security.openshift.io/v1/SecurityContextConstraints" }}
        - --nginx-scc={{ include "nginx-gateway.scc-name" . }}-nginx
        {{- end}}
        {{- if .Values.nginx.nginxOneConsole.dataplaneKeySecretName }}
        - --nginx-one-dataplane-key-secret={{ .Values.nginx.nginxOneConsole.dataplaneKeySecretName }}
          {{- if .Values.nginx.nginxOneConsole.endpointHost }}
        - --nginx-one-telemetry-endpoint-host={{ .Values.nginx.nginxOneConsole.endpointHost }}
          {{- end }}
          {{- if .Values.nginx.nginxOneConsole.endpointPort }}
        - --nginx-one-telemetry-endpoint-port={{ .Values.nginx.nginxOneConsole.endpointPort }}
          {{- end }}
          {{- if .Values.nginx.nginxOneConsole.skipVerify }}
        - --nginx-one-tls-skip-verify
          {{- end }}
        {{- end }}
        env:
        - name: POD_NAMESPACE
          valueFrom:
            fieldRef:
              fieldPath: metadata.namespace
        - name: POD_NAME
          valueFrom:
            fieldRef:
              fieldPath: metadata.name
        - name: POD_UID
          valueFrom:
            fieldRef:
              fieldPath: metadata.uid
        - name: INSTANCE_NAME
          valueFrom:
            fieldRef:
              fieldPath: metadata.labels['app.kubernetes.io/instance']
        - name: IMAGE_NAME
          value: {{ .Values.nginxGateway.image.repository }}:{{ default .Chart.AppVersion .Values.nginxGateway.image.tag }}
        image: {{ .Values.nginxGateway.image.repository }}:{{ default .Chart.AppVersion .Values.nginxGateway.image.tag }}
        imagePullPolicy: {{ .Values.nginxGateway.image.pullPolicy }}
        name: nginx-gateway
        {{- if .Values.nginxGateway.lifecycle }}
        lifecycle:
        {{- toYaml .Values.nginxGateway.lifecycle | nindent 10 }}
        {{- end }}
        {{- if .Values.nginxGateway.resources }}
