  {{- with .spec.addresses }}
  addresses:
    {{- toYaml . | nindent 4 }}
  {{- end }}
  listeners:
    {{- range $listener := .spec.listeners }}
    - name: {{ $listener.name }}
      {{- with $listener.hostname }}
      hostname: {{ . | toYaml }}
      {{- end }}
      port: {{ $listener.port }}
      protocol: {{ $listener.protocol }}
      {{- with $listener.allowedRoutes }}
      allowedRoutes:
        {{- toYaml . | nindent 8 }}
      {{- end }}
      {{- with $listener.tls }}
      tls:
        {{- toYaml . | nindent 8 }}
      {{- end}}
      {{- end }}
  {{- with .spec.tls }}
  tls:
    {{- toYaml . | nindent 4 }}
  {{- end }}
{{- end }}

